import { useEffect, useReducer, useRef, useState } from 'react';
import {
  ACCENT_PRESETS,
  getAccent, setAccent,
  getCellBorder, setCellBorder, type CellBorder,
  getClueFace, setClueFace, type ClueFace,
} from './customize';
import { trapFocus } from '../a11y/trap-focus';
import './customize.css';

interface Props { onClose: () => void; }

/**
 * Customization sheet: accent color, cell border style, clue typography.
 * Lazy-loaded.
 */
export function CustomizeSheet({ onClose }: Props) {
  const ref = useRef<HTMLDivElement>(null);
  const [, force] = useReducer((x: number) => x + 1, 0);
  const [hexInput, setHexInput] = useState(getAccent().replace('#', ''));
  const [hexErr, setHexErr] = useState<string | null>(null);

  useEffect(() => {
    const node = ref.current;
    if (!node) return;
    const release = trapFocus(node);
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => { release(); window.removeEventListener('keydown', onKey); };
  }, [onClose]);

  function applyPreset(v: string) {
    setAccent(v);
    setHexInput(v.replace('#', ''));
    setHexErr(null);
    force();
  }
  function applyHex() {
    const v = hexInput.trim();
    if (!/^[0-9a-fA-F]{6}$/.test(v)) {
      setHexErr('Use a 6-digit hex like 3b82f6.');
      return;
    }
    setAccent(`#${v}`);
    setHexErr(null);
    force();
  }
  function pickBorder(b: CellBorder) { setCellBorder(b); force(); }
  function pickClueFace(f: ClueFace) { setClueFace(f); force(); }

  const accent = getAccent();
  const border = getCellBorder();
  const face = getClueFace();

  return (
    <div className="etch-cust-backdrop" role="dialog" aria-modal="true" aria-label="Customize" onClick={onClose}>
      <div className="etch-cust-sheet" ref={ref} onClick={(e) => e.stopPropagation()}>
        <header>
          <h2>Customize</h2>
          <button onClick={onClose} className="etch-cust-close" aria-label="Close">×</button>
        </header>

        <section>
          <h3>Accent color</h3>
          <div className="etch-cust-swatches" role="radiogroup" aria-label="Accent presets">
            {ACCENT_PRESETS.map(p => (
              <button
                key={p.id}
                type="button"
                role="radio"
                aria-checked={accent.toLowerCase() === p.value.toLowerCase()}
                aria-label={p.label}
                className="etch-cust-swatch"
                style={{ background: p.value }}
                data-selected={accent.toLowerCase() === p.value.toLowerCase() || undefined}
                onClick={() => applyPreset(p.value)}
              />
            ))}
          </div>
          <div className="etch-cust-hex-row">
            <label>
              <span>Custom hex</span>
              <span className="etch-cust-hex-input">
                <span aria-hidden="true">#</span>
                <input
                  type="text"
                  value={hexInput}
                  onChange={(e) => setHexInput(e.target.value)}
                  maxLength={6}
                  inputMode="text"
                  spellCheck={false}
                  aria-label="Custom hex color"
                />
              </span>
            </label>
            <button type="button" className="etch-cust-apply" onClick={applyHex}>Apply</button>
          </div>
          {hexErr && <p className="etch-cust-err" role="alert">{hexErr}</p>}
        </section>

        <section>
          <h3>Cell border</h3>
          <div className="etch-cust-pills" role="radiogroup" aria-label="Cell border">
            {(['sharp', 'rounded', 'dotted'] as CellBorder[]).map(b => (
              <button
                key={b}
                type="button"
                role="radio"
                aria-checked={b === border}
                className={`etch-cust-pill${b === border ? ' is-selected' : ''}`}
                onClick={() => pickBorder(b)}
              >
                {b[0]!.toUpperCase() + b.slice(1)}
              </button>
            ))}
          </div>
        </section>

        <section>
          <h3>Clue typography</h3>
          <div className="etch-cust-pills" role="radiogroup" aria-label="Clue typography">
            {(['numeric', 'blocky', 'etched'] as ClueFace[]).map(f => (
              <button
                key={f}
                type="button"
                role="radio"
                aria-checked={f === face}
                className={`etch-cust-pill${f === face ? ' is-selected' : ''}`}
                onClick={() => pickClueFace(f)}
              >
                {f[0]!.toUpperCase() + f.slice(1)}
              </button>
            ))}
          </div>
          <p className="etch-cust-note">
            Numeric is the default; blocky uses a chunkier font; etched fades subtle.
          </p>
        </section>
      </div>
    </div>
  );
}

export default CustomizeSheet;
